import { component$, useStore, useVisibleTask$, useSignal, $ } from "@builder.io/qwik";
import { routeLoader$, server$, type DocumentHead } from "@builder.io/qwik-city";
import { getFirstPage, getNextPage, type Post } from "../db/database.server";

export const useFeed = routeLoader$(() => {
  return getFirstPage();
});

export const loadMore = server$(function (cursor: number) {
  return getNextPage(cursor);
});

export default component$(() => {
  const initial = useFeed();
  const store = useStore<{ posts: Post[]; loading: boolean; hasMore: boolean; done: boolean }>({
    posts: [...initial.value.posts],
    loading: false,
    hasMore: initial.value.hasMore,
    done: !initial.value.hasMore,
  });
  const sentinel = useSignal<Element>();

  useVisibleTask$(({ cleanup }) => {
    let observer: IntersectionObserver | undefined;
    const loadNext = async () => {
      if (store.loading || !store.hasMore) return;
      store.loading = true;
      const lastId = store.posts.length ? store.posts[store.posts.length - 1].id : 0;
      const result = await loadMore(lastId);
      store.posts.push(...result.posts);
      store.hasMore = result.hasMore;
      store.loading = false;
      if (!result.hasMore) {
        store.done = true;
        observer?.disconnect();
      }
    };
