      for (const entry of entries) {
        if (entry.isIntersecting) {
          loadNext();
        }
      }
    });
    if (sentinel.value) {
      observer.observe(sentinel.value);
    }
    cleanup(() => observer?.disconnect());
  });

  return (
    <main>
      <h1>Feed</h1>
      <ul>
        {store.posts.map((post) => (
          <li key={post.id} data-testid="feed-item">
            <h2>{post.title}</h2>
            <p>{post.body}</p>
          </li>
        ))}
      </ul>
      {store.loading && <div data-testid="feed-loading">Loading…</div>}
      {store.done && <div data-testid="feed-end">End of feed</div>}
      <div data-testid="feed-sentinel" ref={sentinel} />
    </main>
  );
});
```

