/**
 * Server-only SQLite database module.
 *
 * The `.server.ts` extension tells the Qwik optimizer that this module must
 * never be bundled into the client. All `better-sqlite3` imports and queries
 * live here, so no Node-only code can leak into the browser bundle.
 */
import Database from "better-sqlite3";
import { resolve } from "node:path";

export interface Post {
  id: number;
  title: string;
  body: string;
}

export interface PageResult {
  posts: Post[];
  hasMore: boolean;
}

/** Number of posts returned per page (cursor pagination). */
export const PAGE_SIZE = 10;

/** Total number of posts the feed is seeded with. */
export const TOTAL_POSTS = 47;

// The database file lives inside the project directory.
const DB_PATH = resolve(process.cwd(), "feed.db");

// Reuse a single connection across requests within the same module instance.
let dbInstance: Database.Database | null = null;

function getDb(): Database.Database {
  if (dbInstance) {
    return dbInstance;
  }

  const db = new Database(DB_PATH);
  db.pragma("journal_mode = WAL");

  db.exec(`
    CREATE TABLE IF NOT EXISTS posts (
      id    INTEGER PRIMARY KEY,
      title TEXT NOT NULL,
      body  TEXT NOT NULL
    )
  `);

  // Seed exactly 47 posts (Post #1 .. Post #47) when the table is empty.
  const row = db.prepare("SELECT COUNT(*) AS c FROM posts").get() as {
    c: number;
  };
  if (row.c === 0) {
    const insert = db.prepare(
      "INSERT INTO posts (id, title, body) VALUES (?, ?, ?)",
    );
    const seed = db.transaction(() => {
      for (let n = 1; n <= TOTAL_POSTS; n++) {
        insert.run(
          n,
          `Post #${n}`,
          `This is the body text for post number ${n}. It contains some descriptive content to give the feed item a bit of substance.`,
        );
      }
    });
    seed();
  }

  dbInstance = db;
  return db;
}

/** Returns the first page of posts (server-rendered via routeLoader$). */
export function getFirstPage(): PageResult {
  const db = getDb();
  const posts = db
    .prepare("SELECT * FROM posts ORDER BY id ASC LIMIT ?")
    .all(PAGE_SIZE) as Post[];

  const hasMore = posts.length < TOTAL_POSTS;
  return { posts, hasMore };
}

/** Returns the page of posts that come after the given cursor (last loaded id). */
export function getNextPage(cursor: number): PageResult {
  const db = getDb();
  const posts = db
    .prepare("SELECT * FROM posts WHERE id > ? ORDER BY id ASC LIMIT ?")
    .all(cursor, PAGE_SIZE) as Post[];

  const lastId = posts.length ? posts[posts.length - 1].id : cursor;
  const remaining = (
    db
      .prepare("SELECT COUNT(*) AS c FROM posts WHERE id > ?")
      .get(lastId) as { c: number }
  ).c;

  return { posts, hasMore: remaining > 0 };
}

import {
  component$,
  useSignal,
  useStore,
  useVisibleTask$,
  type QwikIntrinsicElements,
} from "@builder.io/qwik";
import { routeLoader$, server$, type DocumentHead } from "@builder.io/qwik-city";
import {
  getFirstPage,
  getNextPage,
  type PageResult,
  type Post,
} from "../db/database.server";

/**
 * Initial page is produced on the server and embedded in the SSR HTML, so the
 * first 10 posts are visible without any client JavaScript.
 */
export const useFeed = routeLoader$(() => {
  return getFirstPage();
});

/**
 * RPC used by the client to load every subsequent page. It accepts the cursor
 * (the id of the last item already loaded) and returns the next page plus
 * whether more posts remain. All database access stays inside this server
 * function, so nothing Node-only reaches the browser.
 */
export const loadMore = server$(function (cursor: number): PageResult {
  return getNextPage(cursor);
});

export default component$(() => {
  const initial = useFeed();

  const state = useStore<{
    posts: Post[];
    loading: boolean;
    hasMore: boolean;
    done: boolean;
  }>({
    posts: [...initial.value.posts],
    loading: false,
    hasMore: initial.value.hasMore,
    done: !initial.value.hasMore,
  });

  const sentinel = useSignal<HTMLElement>();

  useVisibleTask$(({ cleanup }) => {
    let observer: IntersectionObserver | undefined;

    const loadNext = async () => {
      // Guard against overlapping fetches and fetching past the end.
      if (state.loading || !state.hasMore) {
        return;
      }
      state.loading = true;

      const lastId = state.posts.length
        ? state.posts[state.posts.length - 1].id
        : 0;

      try {
        const result = await loadMore(lastId);
        // Append only newly fetched posts (cursor guarantees no duplicates).
        state.posts.push(...result.posts);
        state.hasMore = result.hasMore;
        if (!result.hasMore) {
          state.done = true;
          observer?.disconnect();
        }
      } finally {
        state.loading = false;
      }
    };

    observer = new IntersectionObserver((entries) => {
      for (const entry of entries) {
        if (entry.isIntersecting) {
          loadNext();
        }
      }
    });

    if (sentinel.value) {
      observer.observe(sentinel.value);
    }

    cleanup(() => observer?.disconnect());
  });

  return (
    <main class="feed">
      <header class="feed__header">
        <h1>Infinite Feed</h1>
        <p>Scroll down to load more posts.</p>
      </header>

      <ul class="feed__list">
        {state.posts.map((post) => (
          <li
            key={post.id}
            data-testid="feed-item"
            class="feed__item"
          >
            <h2 class="feed__item-title">{post.title}</h2>
            <p class="feed__item-body">{post.body}</p>
          </li>
        ))}
      </ul>

      {/* Loading indicator: present in the DOM only while a page is fetched. */}
      {state.loading && (
        <div data-testid="feed-loading" class="feed__loading">
          Loading more posts…
        </div>
      )}

      {/* End-of-feed indicator: shown once the last post has been loaded. */}
      {state.done && (
        <div data-testid="feed-end" class="feed__end">
          End of feed
        </div>
      )}

      {/* Sentinel watched by the IntersectionObserver. */}
      <div
        data-testid="feed-sentinel"
        ref={sentinel}
        class="feed__sentinel"
      />
    </main>
  );
});

export const head: DocumentHead = {
  title: "Infinite Feed",
  meta: [
    {
      name: "description",
      content: "An infinite-scroll feed built with Qwik City and SQLite.",
    },
  ],
};

